import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { ResponsiveChartContainer, PieChart, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface VaccinationStatus {
  dosesReceived: number;
  nextDueDate: string;
  coveragePercentage: number;
}

interface DoseHistory {
  dose: number;
  date: string;
  vaccine: string;
}

interface VaccinationData {
  vaccinationStatus: VaccinationStatus;
  doseHistory: DoseHistory[];
}

interface MetaData {
  theme: string;
  dataMode: string;
  layout: string;
  primaryColor: string;
  accentColor: string;
}

export default function Widget() {
  const vaccinationData = response.data as VaccinationData;
  const metaData = response.meta as MetaData;
  const { vaccinationStatus, doseHistory } = vaccinationData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#000000' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#FFFFFF', mb: 1 }}>
              Vaccination Tracker
            </Typography>
            <Stack direction="row" spacing={0.5}>
              {doseHistory.map((dose) => (
                <Chip
                  key={dose.dose}
                  label={`${dose.vaccine} Dose ${dose.dose}: ${dose.date}`}
                  sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: metaData.accentColor, color: '#000000' }}
                />
              ))}
            </Stack>
          </Box>

          <Box>
            <Typography variant="body2" sx={{ color: '#FFFFFF' }}>
              Doses Received
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: metaData.primaryColor }}>
              {vaccinationStatus.dosesReceived}
            </Typography>
            <Typography variant="body2" sx={{ color: '#FFFFFF' }}>
              Next Due Date: {vaccinationStatus.nextDueDate}
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'pie',
                  data: [
                    { value: vaccinationStatus.coveragePercentage, label: 'Coverage', color: metaData.primaryColor },
                    { value: 100 - vaccinationStatus.coveragePercentage, label: 'Remaining', color: '#CCCCCC' }
                  ]
                }
              ]}
            >
              <ChartsClipPath id={'clipPathId'} />
              <PieChart />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
